type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// webhookTestPayload is the payload sent to test the webhook
type webhookTestPayload struct {
	Message string `json:"message"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Security: Block private/internal IP addresses and localhost to prevent SSRF attacks
	if isPrivateIP(parsedURL.Hostname()) {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL cannot point to private or internal addresses",
		})
	}

	// Create a custom HTTP client with timeout and security controls
	client := &http.Client{
		Timeout: 5 * time.Second,
		// Security: Prevent redirects to avoid potential SSRF bypasses
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Prepare test payload
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	_, err = json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Create request with context for cancellation control
	httpReq, err := http.NewRequestWithContext(context.Background(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Set headers for the test request
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")
	httpReq.Header.Set("Accept", "application/json")

