		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isPrivateIP checks if the given hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Check for localhost variants
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0:0:0:0:0:0:0:1" {
		return true
	}

	// Try to resolve the hostname to check for private IPs
	addrs, err := net.LookupHost(hostname)
	if err != nil {
		// If we can't resolve, be conservative and block it
		return true
	}

	for _, addr := range addrs {
		ip := net.ParseIP(addr)
		if ip == nil {
			continue
		}

		// Check for loopback addresses
		if ip.IsLoopback() {
			return true
		}

		// Check for private addresses (RFC 1918, RFC 4193, etc.)
		if ip.IsPrivate() {
			return true
		}

		// Check for link-local addresses
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}

		// Check for multicast addresses
		if ip.IsMulticast() {
			return true
		}

		// Check for unspecified address
		if ip.IsUnspecified() {
			return true
		}
	}

	return false
}

