// isPrivateHost checks if a hostname resolves to a private IP address
func isPrivateHost(hostname string) bool {
	// Check for localhost variants
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0.0.0.0" {
		return true
	}

	// Resolve the hostname to IP addresses
	addrs, err := net.LookupHost(hostname)
	if err != nil {
		// If we can't resolve, be conservative and reject
		return true
	}

	for _, addr := range addrs {
		ip := net.ParseIP(addr)
		if ip == nil {
			continue
		}

		// Check for loopback addresses
		if ip.IsLoopback() {
			return true
		}

		// Check for link-local addresses
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}

		// Check for private addresses (RFC 1918 and others)
		if isPrivateIP(ip) {
			return true
		}
	}

	return false
}

// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ip net.IP) bool {
	// IPv4 private ranges
	privateRanges := []struct {
		start net.IP
		end   net.IP
	}{
		{net.ParseIP("10.0.0.0"), net.ParseIP("10.255.255.255")},
		{net.ParseIP("172.16.0.0"), net.ParseIP("172.31.255.255")},
		{net.ParseIP("192.168.0.0"), net.ParseIP("192.168.255.255")},
		{net.ParseIP("169.254.0.0"), net.ParseIP("169.254.255.255")}, // Link-local
		{net.ParseIP("127.0.0.0"), net.ParseIP("127.255.255.255")},   // Loopback
		{net.ParseIP("0.0.0.0"), net.ParseIP("0.255.255.255")},       // Current network
		{net.ParseIP("100.64.0.0"), net.ParseIP("100.127.255.255")},  // Carrier-grade NAT
	}

	for _, r := range privateRanges {
		if bytes.Compare(ip, r.start) >= 0 && bytes.Compare(ip, r.end) <= 0 {
			return true
		}
	}

	// IPv6 unique local addresses (fc00::/7)
	if ip.To4() == nil && len(ip) == net.IPv6len {
		if ip[0]&0xfe == 0xfc {
			return true
		}
		// IPv6 loopback (::1)
		if ip.Equal(net.ParseIP("::1")) {
			return true
		}
	}

	return false
}

