// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Security: Validate host to prevent SSRF attacks
	// Block localhost, private IP ranges, and internal network addresses
	if !isValidHost(parsedURL.Hostname()) {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL points to an invalid or restricted address",
		})
	}

	// Create a custom HTTP client with timeout and security settings
	client := &http.Client{
		Timeout: 5 * time.Second,
		// Prevent redirects to avoid potential SSRF through redirects
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Create context with timeout for the request
	reqCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Send GET test request to webhook URL as specified in requirements
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Set appropriate headers
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isValidHost checks if the hostname is not a private/internal address
// to prevent Server-Side Request Forgery (SSRF) attacks
func isValidHost(hostname string) bool {
	// Block empty hostnames
	if hostname == "" {
		return false
	}

	// Block localhost variants
	localhostNames := map[string]bool{
		"localhost":     true,
		"localhost.":    true,
		"127.0.0.1":     true,
		"::1":           true,
		"0.0.0.0":       true,
		"[::1]":         true,
		"[0000:0000:0000:0000:0000:0000:0000:0001]": true,
	}
	if localhostNames[hostname] {
		return false
	}

	// Check for localhost suffixes/prefixes
	if len(hostname) > 9 && hostname[:10] == "127." {
		return false
	}

	// Block common internal TLDs
	internalTLDs := []string{".local", ".internal", ".corp", ".home", ".lan"}
	for _, tld := range internalTLDs {
		if len(hostname) > len(tld) && hostname[len(hostname)-len(tld):] == tld {
			return false
		}
	}

	// Block IPv6 loopback variations
	if hostname == "::" || hostname == "[::]" {
		return false
	}

	// Block IPv4-mapped IPv6 loopback
	if hostname == "[::ffff:127.0.0.1]" || hostname == "::ffff:127.0.0.1" {
		return false
	}

	return true
}

