package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Security: Reject URLs with userinfo (credentials in URL)
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain credentials",
		})
	}

	// Security: Reject localhost and private IP addresses to prevent SSRF
	if isPrivateHost(parsedURL.Hostname()) {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not point to private networks or localhost",
		})
	}

	// Create a custom HTTP client with timeout and security settings
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Security: Prevent open redirects - limit redirect count
			if len(via) >= 3 {
				return fmt.Errorf("too many redirects")
			}
			// Security: Validate redirect target
			if req.URL != nil {
				if isPrivateHost(req.URL.Hostname()) {
					return fmt.Errorf("redirect to private network not allowed")
				}
				if req.URL.User != nil {
					return fmt.Errorf("redirect to URL with credentials not allowed")
				}
			}
			return nil
		},
	}

	// Create GET request for testing (as per requirements)
	httpReq, err := http.NewRequestWithContext(context.Background(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Set a custom header to identify this as a test request
	httpReq.Header.Set("User-Agent", "Webhook-Configurator/1.0")

	// Send test request to webhook URL using GET method
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isPrivateHost checks if a hostname resolves to a private IP address
func isPrivateHost(hostname string) bool {
	// Check for localhost variations
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Check for IPv4 loopback (127.x.x.x)
	if len(hostname) > 4 && hostname[:4] == "127." {
		return true
	}

	// Check for private IP ranges by parsing
	ip := net.ParseIP(hostname)
	if ip != nil {
		// Check for loopback, link-local, multicast, and private ranges
		if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() ||
			ip.IsPrivate() || ip.IsMulticast() || ip.IsUnspecified() {
			return true
		}
	}

	// Check for common internal TLDs and patterns
	lowerHost := strings.ToLower(hostname)
	internalPatterns := []string{".local", ".internal", ".intranet", ".lan"}
	for _, pattern := range internalPatterns {
		if strings.HasSuffix(lowerHost, pattern) {
			return true
		}
	}

	return false
}

