// isValidHost checks if the hostname is allowed (not localhost, private IP, or internal)
func isValidHost(hostname string) bool {
	// Block empty hostnames
	if hostname == "" {
		return false
	}

	// Block localhost variants
	localhostNames := map[string]bool{
		"localhost":     true,
		"127.0.0.1":     true,
		"::1":           true,
		"0.0.0.0":       true,
		"[::1]":         true,
		"[::]":          true,
		"0000:0000:0000:0000:0000:0000:0000:0001": true,
		"0000:0000:0000:0000:0000:0000:0000:0000": true,
	}
	if localhostNames[hostname] {
		return false
	}

	// Check for localhost subdomains
	if len(hostname) > 10 && hostname[len(hostname)-10:] == ".localhost" {
		return false
	}

	// Check for numeric IP addresses (IPv4 and IPv6)
	ip := net.ParseIP(hostname)
	if ip != nil {
		// It's a valid IP address, check if it's private
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() ||
			ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() {
			return false
		}
	}

	// Block common internal TLDs and patterns
	blockedPatterns := []string{
		".internal",
		".local",
		".corp",
		".home",
		".lan",
		".intranet",
	}
	for _, pattern := range blockedPatterns {
		if containsSubstring(hostname, pattern) {
			return false
		}
	}

	return true
}

// containsSubstring checks if s contains substr
func containsSubstring(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > len(substr) &&
		(s[:len(substr)] == substr || s[len(s)-len(substr):] == substr ||
			containsMiddle(s, substr)))
}

// containsMiddle checks if substr appears in the middle of s
func containsMiddle(s, substr string) bool {
	for i := 1; i < len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

