package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response for webhook configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook_url field
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a context with timeout for the request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create test GET request to validate the webhook URL
	req, err := http.NewRequestWithContext(reqCtx, http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	// Send the test request
	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded with a successful status
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		// Save the configuration (in a real application, this would persist to database)
		// For demonstration, we'll just return success

		return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
			Success: true,
			Message: "Webhook configured successfully",
		})
	}

	// Webhook returned non-success status
	return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
		Success: false,
		Message: fmt.Sprintf("Webhook returned status code: %d", resp.StatusCode),
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

