// isPrivateHost checks if a hostname resolves to a private IP address
// This prevents Server-Side Request Forgery (SSRF) attacks
func isPrivateHost(hostname string) bool {
	// Check for common localhost variants
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0.0.0.0" {
		return true
	}

	// Check for IPv4 loopback (127.x.x.x)
	// Simple check for 127. prefix
	if len(hostname) > 4 && hostname[:4] == "127." {
		return true
	}

	// Check for IPv6 loopback
	if hostname == "::" || hostname == "::ffff:127.0.0.1" {
		return true
	}

	// Check for link-local addresses (169.254.x.x)
	if len(hostname) > 8 && hostname[:8] == "169.254." {
		return true
	}

	// Check for private IPv4 ranges
	// 10.x.x.x
	if len(hostname) > 3 && hostname[:3] == "10." {
		return true
	}

	// 172.16.x.x - 172.31.x.x
	if len(hostname) > 7 && hostname[:7] == "172.16." ||
		len(hostname) > 7 && hostname[:7] == "172.17." ||
		len(hostname) > 7 && hostname[:7] == "172.18." ||
		len(hostname) > 7 && hostname[:7] == "172.19." ||
		len(hostname) > 7 && hostname[:7] == "172.20." ||
		len(hostname) > 7 && hostname[:7] == "172.21." ||
		len(hostname) > 7 && hostname[:7] == "172.22." ||
		len(hostname) > 7 && hostname[:7] == "172.23." ||
		len(hostname) > 7 && hostname[:7] == "172.24." ||
		len(hostname) > 7 && hostname[:7] == "172.25." ||
		len(hostname) > 7 && hostname[:7] == "172.26." ||
		len(hostname) > 7 && hostname[:7] == "172.27." ||
		len(hostname) > 7 && hostname[:7] == "172.28." ||
		len(hostname) > 7 && hostname[:7] == "172.29." ||
		len(hostname) > 7 && hostname[:7] == "172.30." ||
		len(hostname) > 7 && hostname[:7] == "172.31." {
		return true
	}

	// 192.168.x.x
	if len(hostname) > 8 && hostname[:8] == "192.168." {
		return true
	}

	// fc00::/7 (IPv6 unique local addresses)
	if len(hostname) > 2 && (hostname[:2] == "fc" || hostname[:2] == "fd") {
		return true
	}

	// fe80::/10 (IPv6 link-local addresses)
	if len(hostname) > 3 && hostname[:3] == "fe8" {
		return true
	}

	return false
}

